powerpagecomponent.content:
{
  "copy": "<!-- ENTER: Accounting -->

{% comment %} DEBUG: Adding debug output to troubleshoot period dropdown issue {% endcomment %}
{% include 'snippet' snippet_name:'FetchXML - SetupQuery' %}

{% comment %} ~pageAccounting {% endcomment %} 

{% if is_admin != true %}
    {% if has_admin_backdoor == true %}
        <!-- Smart redirect for admins in testing mode -->
        <div class="container mt-5">
            <div class="alert alert-info text-center p-4">
                <h4><i class="fas fa-flask"></i> Administrator Testing Mode Active</h4>
                <p class="mb-3">You have removed your Administrator role for testing purposes.</p>
                <button onclick="restoreAdminAccessFromPage()" class="btn btn-primary btn-lg">
                    <i class="fas fa-user-cog"></i> Restore Administrator Access
                </button>
                <hr class="my-3">
                <p class="text-muted">
                    <small>Or continue testing as: 
                        <a href="/Branch" class="text-decoration-none">Branch Manager</a> | 
                        <a href="/Loan-Officer" class="text-decoration-none">Loan Officer</a>
                    </small>
                </p>
            </div>
        </div>

        <script>
        function restoreAdminAccessFromPage() {
            const button = event.target;

            // Show loading state
            button.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Restoring...';
            button.disabled = true;

            // Get the admin role ID and contact ID from global variables
            const adminRoleId = window.adminRoleId || '';
            const contactId = window.contactId || '';

            if (!adminRoleId || !contactId) {
                alert('Error: Missing admin role ID or contact ID. Cannot restore admin access.');
                button.innerHTML = '<i class="fas fa-user-cog"></i> Restore Administrator Access';
                button.disabled = false;
                return;
            }

            // Call the role assignment API directly
            const url = window.urlContactWebRole;
            if (!url || url.trim() === '') {
                console.error('❌ ERROR: window.urlContactWebRole is not configured!');
                alert('ERROR: Administrator role recovery system is not properly configured.\n\nThe role assignment API URL is missing from system settings.\n\nPlease contact your system administrator to:\n1. Configure the role assignment URL in the setup record\n2. Manually restore your Administrator web role\n\nWithout this configuration, automated role recovery cannot function.');
                button.innerHTML = '<i class="fas fa-user-cog"></i> Restore Administrator Access';
                button.disabled = false;
                return;
            }

            if (!url.startsWith('http')) {
                console.error('❌ ERROR: window.urlContactWebRole appears invalid:', url);
                alert('ERROR: Role assignment API URL appears to be misconfigured.\n\nExpected format: https://...\nActual value: ' + url + '\n\nPlease contact your system administrator to correct the URL in system settings.');
                button.innerHTML = '<i class="fas fa-user-cog"></i> Restore Administrator Access';
                button.disabled = false;
                return;
            }

            // Make API call to restore admin role
            fetch(url, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    action: 'add',
                    contactId: contactId,
                    roleId: adminRoleId
                })
            })
            .then(response => {
                if (response.ok) {
                    button.innerHTML = '<i class="fas fa-check"></i> Restored! Redirecting...';

                    // Wait 3 seconds for role assignment to take effect, then redirect
                    setTimeout(() => {
                        window.location.href = '/Accounting';
                    }, 3000);

                } else {
                    throw new Error('API call failed');
                }
            })
            .catch(error => {
                console.error('Error restoring admin role:', error);
                alert('Failed to restore admin role. Please try the manual method via your Profile page.');
                button.innerHTML = '<i class="fas fa-user-cog"></i> Restore Administrator Access';
                button.disabled = false;
            });
        }
        </script>
    {% else %}
        <!-- Normal redirect for non-admin users -->
        <script>
            (function() {
                let redir = "~/";

                console.log("Accounting: G_Roles.isAdmin: " + G_Roles.isAdmin + "; isAssign: " + G_Roles.isAssign);
                console.log("Accounting: G_Roles.isBranch: " + G_Roles.isBranch + "; G_Roles.isLO: " + G_Roles.isLO);
                console.log("Accounting: Full G_Roles object:", G_Roles);

                if (G_Roles.isAdmin) {
                    redir = "";
                } else if (G_Roles.isAssign || (window.DEBUG_AdminVars && window.DEBUG_AdminVars.has_admin_backdoor)) {
                    redir = "~/Accounting/Profiles";
                } else if (G_Roles.isBranch) {
                    redir = "/Branch";
                } else if (G_Roles.isLO) {
                    redir = "/Loan-Officer";
                }

                if (redir != "")
                {
                    console.log("Accounting page: Access denied: Admin permission required. Redir=" + redir);
                    // Delay the redirect slightly to allow for logging
                    setTimeout(function() {
                        window.location.href = redir;
                    }, 100);
                }
            })();
        </script>
    {% endif %}

{% else %}

<div class="row sectionBlockLayout text-start" style="display: flex; flex-wrap: wrap; margin: 0px; min-height: auto; padding: 8px;">
	<div class="container" style="display: flex; flex-wrap: wrap;">
		<div class="col-lg-12 columnBlockLayout email-modal-container my-2 my-md-4 my-lg-5" style="flex-grow: 1; display: flex; flex-direction: column; min-width: 250px; word-break: break-word; padding: 16px;">
			{% include 'snippet' snippet_name:'FetchXML - BranchQuery' %}
			{% include 'snippet' snippet_name:'Commission Filter' %}                               {% comment %} CENTRALIZED FILTERING: applies all permission and page-specific filters, sets cpCommCount, cpCommTotal, cpAdjuCount, cpAdjuTotal {% endcomment %}
			{% include 'snippet' snippet_name:'FetchXML - Current Period' %}

			<div id="divAccounting" class="accountingContainer">
				<div class="accountingHeading">
					<h1 style="text-align: left;">

						Accounting

					</h1>
				</div>

				<div class="admin-panel">
					{% include 'snippet' snippet_name:'Current Period Selection' %}           {% comment %}    Period Selection Dropdown                       {% endcomment %}
					{% include 'snippet' snippet_name:'Admin Panel Navigation' %}             {% comment %}    Setup, Profiles, and also Assignment buttons    {% endcomment %}
				</div>
			</div>

			{% include 'snippet' snippet_name:'Dashboard Details' %}      {% comment %}                          {% endcomment %}

			<div class="row sectionBlockLayout" style="display: flex; flex-wrap: wrap; padding: 8px; margin: 0px; min-height: 25px;"></div>

			<div class="ppFlexContainer" style="display: flex; align-items: center; padding: 8px 0 8px 0;">

				{% if cfgPrintEnabled %}                  {% comment %}      TODO8: this logic is duplicated across /web-pages/Accounting|Region|Branch|LoanOfficer                tag=2504021442              {% endcomment %} 
					<div onclick="printpage()" data-component-theme="portalThemeColor10" class="ppFlexContainer p911button">
						<p style="text-align: left; color: var(--portalThemeColor5); font-size: 18px;">
							<b aria-label="Text Commission Profile" style="position: relative;">
								Print
							</b>
						</p>
						<img src="/icon-print.png" alt="icon-print" name="icons-print.png" style="width: 28.67%; height: 28px; max-width: 100%;" />
					</div>
				{% endif %}


				<div data-component-theme="portalThemeColor10" class="ppFlexContainer p911button">
					<a href="/Branch{% if request.query %}{{request.query}}{% endif %}" class="anchor-inherit-styles"
						 onclick="spinShow(true); setTimeout(function() { return true; }, 300);"">
						<p style="text-align: left; color: var(--portalThemeColor5); font-size: 18px;">​
							<b>Branch</b>
						</p>
					</a>
				</div>

				<div data-component-theme="portalThemeColor10" class="ppFlexContainer p911button">
					<a href="/Loan-Officer{% if request.query %}{{request.query}}{% endif %}" class="anchor-inherit-styles"
						 onclick="spinShow(true); setTimeout(function() { return true; }, 300);"">
						<p style="text-align: left; color: var(--portalThemeColor5); font-size: 18px;">​
							<b>Loan Officer</b>
						</p>
					</a>
				</div>

			</div>

			<div id="divAcctgPrimaryCommTbl" class="row sectionBlockLayout" style="display: flex; flex-wrap: wrap; padding: 8px; margin: 0px; min-height: 25px;"></div>
			{%comment%}               'Primary Commissions Table' is a template                {%endcomment%}
			{% include 'Primary Commissions Table' %}

			<div  id="divAcctgPrimaryAdjTbl" class="row sectionBlockLayout" style="display: flex; flex-wrap: wrap; padding: 8px; margin: 0px; min-height: 25px;"></div>
			{%comment%}                Is a template                                           {%endcomment%}
			{% include 'Primary Adjustments Table' %}

			{% include 'snippet' snippet_name:'Email Dialog' %}
			{% include 'Email Modal' %}
		</div>
	</div>
</div>

{% endif %}

<!-- LEAVE: Accounting -->

",
  "customjavascript": "
",
  "displayorder": 2,
  "enablerating": false,
  "enabletracking": false,
  "excludefromsearch": false,
  "feedbackpolicy": 756150000,
  "hiddenfromsitemap": true,
  "isroot": false,
  "pagetemplateid": "cd587cbe-a61f-4c11-a750-6d0235a784ef",
  "parentpageid": "362995e0-7dc5-4bbf-9595-062f468d2d44",
  "partialurl": "Accounting",
  "publishingstateid": "2177b470-e9b1-4c6b-8f73-91dc8f4d21e9",
  "rootwebpageid": "f9e4fac8-bb2b-fab4-760d-3e3ce999cadb",
  "sharedpageconfiguration": false,
  "summary": "<p>This is a sample landing page designed to be a starting point for your website</p>
",
  "title": "Accounting"
}

