<div class="row sectionBlockLayout text-start" style="display: flex; flex-wrap: wrap; margin: 0px; min-height: auto; padding: 8px;">
	<div class="container" style="display: flex; flex-wrap: wrap;">
		<div class="col-lg-12 columnBlockLayout email-modal-container my-2 my-md-4 my-lg-5" style="flex-grow: 1; display: flex; flex-direction: column; min-width: 250px; word-break: break-word; padding: 16px;">
